module RefModule(
    A,
    B,
    SEL,
    Y,
    VPWR,
    VGND
);input A;
    input B;
    input SEL;
    output Y;
    input VPWR;
    input VGND;

    wire not_sel;
    wire and1_out;
    wire and2_out;

    // Using basic NOT and AND operations instead of specific library cells
  assign Y = and1_out | and2_out;
  assign and2_out = B & SEL;
  assign and1_out = A & not_sel;

  assign not_sel = ~SEL;

endmodule
